use std::collections::VecDeque;

fn calculate_edit_distance(s1: &str, s2: &str) -> i32 {
    let chars1: Vec<char> = s1.chars().collect();
    let chars2: Vec<char> = s2.chars().collect();
    let len1 = chars1.len() as usize;
    let len2 = chars2.len() as usize;

    if len1 == 0 { return (len2) as i32; }
    if len2 == 0 { return (len1) as i32; }

    let mut dp: Vec<i32> = vec![0; (len2 + 1) as usize];
    for j in 0..=len2 { dp[j] = j as i32; }

    let mut prev_row: Vec<i32> = vec![0; (len2 + 1) as usize];
    for j in 0..=len2 { prev_row[j] = j as i32; }

    for i in 1..=len1 {
        let mut current_row: Vec<i32> = vec![0; (len2 + 1) as usize];
        current_row[0] = i as i32;

        for j in 1..=len2 {
            let cost = if chars1[i - 1] == chars2[j - 1] { 0 } else { 1 };
            let substitution = prev_row[j - 1] + cost;
            let insertion = current_row[j - 1] + 1;
            let deletion = dp[j] + 1;
            current_row[j] = (substitution.min(insertion)).min(deletion);
        }
        dp = current_row.clone();
    }

    dp[len2 as usize]
}

use std::cmp::{min, max};

struct WordListComparer {
    data: Vec<String>,
}

impl WordListComparer {
    fn new(words: Vec<String>) -> Self {
        WordListComparer { data: words }
    }

    fn calculate_edit_distance(&self, s1: &str, s2: &str) -> i32 {
        let m = s1.chars().collect::<Vec<char>>().len();
        let n = s2.chars().collect::<Vec<char>>().len();

        let mut dp = vec![vec![0; (n + 1) as usize]; (m + 1).max(1)];

        for i in 0..=m {
            dp[i].resize((n + 1) as usize, 0);
        }

        for i in 0..=m {
            for j in 0..=n {
                if i == 0 && j == 0 {
                    continue;
                }

                let cost = if i > 0 && j > 0 {
                    s1.chars().nth(i-1) == s2.chars().nth(j-1)
                } else {
                    false
                };

                if i == 0 {
                    dp[i][j] = j as i32;
                } else if j == 0 {
                    dp[i][j] = i as i32;
                } else {
                    let deletion_cost = dp[i-1][j] + 1;
                    let insertion_cost = dp[i][j-1] + 1;
                    let substitution_match_cost = if cost {
                        dp[i-1][j-1]
                    } else {
                        dp[i-1][j-1] + 1
                    };
                    dp[i][j] = min(deletion_cost, min(insertion_cost, substitution_match_cost));
                }
            }
        }

        dp[m][n]
    }
}

fn main() {
    let comparer = WordListComparer::new(vec!["kitten".to_string(), "sitting".to_string()]);
    let distance = comparer.calculate_edit_distance("saturday", "sunday");
    println!("The edit distance is: {}", distance);
}

