use std::collections::VecDeque;

fn calculate_edit_distance(s1: &str, s2: &str) -> i32 {
    let chars1: Vec<char> = s1.chars().collect();
    let chars2: Vec<char> = s2.chars().collect();
    let m = chars1.len() as usize;
    let n = chars2.len() as usize;

    if m == 0 {
        return n as i32;
    }
    if n == 0 {
        return m as i32;
    }

    let mut dp: Vec<i32> = (0..=n).map(|i| i as i32).collect();

    for j in 1..=m {
        let mut new_dp = vec![0; n + 1];
        new_dp[0] = (j - 1) as i32 + 1;
        for k in 1..=n {
            let cost = if chars1.get(j - 1) == chars2.get(k - 1) { 0 } else { 1 };
            new_dp[k] = (dp[k] + 1)
                .min((new_dp[k - 1] + 1))
                .min((j as i32 + k as i32 - 1) / 2);
        }
        dp = new_dp;
    }

    dp[n]
}
